import React, { useEffect, useState } from 'react';
import { get, post } from '../api';

export default function UsersList() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [processing, setProcessing] = useState(false);

  async function fetchUsers() {
    setLoading(true);
    try {
      const res = await get('/api/admin-lists/users');
      setUsers(res.data);
    } catch (err) {
      console.error(err);
      alert('Failed to load participants');
    } finally {
      setLoading(false);
    }
  }

  async function removeDuplicates() {
    if (!window.confirm('This will delete duplicate participants (keep earliest). Continue?')) return;
    setProcessing(true);
    try {
      const res = await post('/api/admin-lists/users/remove-duplicates', {});
      alert(`Deleted ${res.data.deleted} duplicate participants`);
      await fetchUsers();
    } catch (err) {
      console.error(err);
      alert('Failed to remove duplicates');
    } finally {
      setProcessing(false);
    }
  }

  useEffect(() => {
    fetchUsers();
  }, []);

  const calculateAge = (dob) => {
    if (!dob) return '-';
    const birthDate = new Date(dob);
    const today = new Date();
    let age = today.getFullYear() - birthDate.getFullYear();
    const monthDiff = today.getMonth() - birthDate.getMonth();
    if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birthDate.getDate())) {
      age--;
    }
    return age >= 0 ? age : '-';
  };

  return (
    <div>
      <div style={{ marginBottom: 12 }}>
        <button onClick={fetchUsers} disabled={loading} style={{ marginRight: 8 }}>Refresh</button>
        <button onClick={removeDuplicates} disabled={processing}>Remove Duplicates (by Phone)</button>
      </div>
      {loading ? (
        <div>Loading...</div>
      ) : (
        <table border="1" cellPadding="8" style={{ borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <th>Id</th>
              <th>Phone</th>
              <th>Consent</th>
              <th>Phone Verified</th>
              <th>Saved Address</th>
              <th>Name</th>
              <th>Age</th>
              <th>Sex</th>
              <th>Created At</th>
            </tr>
          </thead>
          <tbody>
            {users.map(u => (
              <tr key={u.id}>
                <td>{u.id}</td>
                <td>{u.phone}</td>
                <td>{u.consentAccepted ? 'Yes' : 'No'}</td>
                <td>{u.phoneVerified ? 'Yes' : 'No'}</td>
                <td>{u.savedAddress}</td>
                <td>{u.childProfiles && u.childProfiles.length > 0 ? u.childProfiles.map(c => c.name).join(', ') : '-'}</td>
                <td>{u.childProfiles && u.childProfiles.length > 0 ? u.childProfiles.map(c => calculateAge(c.dateOfBirth)).join(', ') : '-'}</td>
                <td>{u.childProfiles && u.childProfiles.length > 0 ? u.childProfiles.map(c => c.sex || '-').join(', ') : '-'}</td>
                <td>{new Date(u.createdAt).toLocaleString()}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}
